export interface HistoricalDayEvent {
  month: number;
  day: number;
  year: number;
  title: string;
  description: string;
  whyItMatters: string;
  category: "War" | "Science" | "Politics" | "Culture" | "Exploration" | "Economics" | "Revolution" | "Technology" | "Diplomacy" | "Philosophy";
}

export const thisDayEvents: HistoricalDayEvent[] = [
  // January
  { month: 1, day: 1, year: 1863, title: "Emancipation Proclamation Takes Effect", description: "President Abraham Lincoln's executive order declared all enslaved people in Confederate states to be free. While it did not immediately free all enslaved people, it fundamentally transformed the character of the Civil War into a fight for human freedom.", whyItMatters: "The proclamation established the precedent that executive power can be wielded for sweeping social justice, a principle still debated in modern governance.", category: "Politics" },
  { month: 1, day: 2, year: 1492, title: "Fall of Granada Ends Reconquista", description: "The Nasrid dynasty surrendered Granada to Ferdinand and Isabella, ending nearly 800 years of Muslim rule in the Iberian Peninsula. This event unified Spain and set the stage for the Age of Exploration.", whyItMatters: "The consolidation of Spain directly enabled Columbus's voyage later that year, reshaping global history and the modern concept of nation-states.", category: "War" },
  { month: 1, day: 3, year: 1521, title: "Martin Luther Excommunicated", description: "Pope Leo X issued the papal bull Decet Romanum Pontificem, excommunicating Martin Luther from the Catholic Church. Luther's 95 Theses had already sparked a religious revolution across Europe.", whyItMatters: "The Protestant Reformation that followed reshaped Western civilization, establishing principles of individual conscience and institutional accountability.", category: "Culture" },
  { month: 1, day: 4, year: 1643, title: "Isaac Newton Born", description: "Isaac Newton was born in Woolsthorpe, England. He would go on to develop the laws of motion, universal gravitation, and calculus, fundamentally changing humanity's understanding of the physical world.", whyItMatters: "Newton's scientific method and mathematical framework remain the foundation of modern physics, engineering, and technology.", category: "Science" },
  { month: 1, day: 5, year: 1933, title: "Construction of Golden Gate Bridge Begins", description: "Workers broke ground on the Golden Gate Bridge in San Francisco. The suspension bridge would become one of the most recognizable structures in the world upon its completion in 1937.", whyItMatters: "The project demonstrated that ambitious infrastructure investment during economic crises can create lasting value and national symbols of resilience.", category: "Technology" },
  { month: 1, day: 6, year: 1412, title: "Joan of Arc Born", description: "Jeanne d'Arc was born in Domremy, France. The peasant girl would claim divine guidance and lead the French army to pivotal victories during the Hundred Years' War before her capture and execution at age 19.", whyItMatters: "Joan's story endures as a symbol of courage against overwhelming odds and the power of conviction in shaping history.", category: "War" },
  { month: 1, day: 7, year: 1610, title: "Galileo Observes Jupiter's Moons", description: "Galileo Galilei first observed three of Jupiter's four largest moons through his telescope, confirming that not all celestial bodies orbit Earth. This discovery provided crucial evidence for the Copernican heliocentric model.", whyItMatters: "Galileo's observations fundamentally challenged established authority and demonstrated that empirical evidence must prevail over dogma.", category: "Science" },
  { month: 1, day: 8, year: 1790, title: "First State of the Union Address", description: "President George Washington delivered the first annual message to Congress in New York City. He spoke about national defense, foreign relations, and the importance of education.", whyItMatters: "This tradition of presidential accountability to the legislature remains a cornerstone of democratic governance worldwide.", category: "Politics" },
  { month: 1, day: 9, year: 1799, title: "Income Tax Introduced in Britain", description: "British Prime Minister William Pitt the Younger introduced the first income tax to fund the war against Napoleon. The tax was initially set at two shillings per pound on incomes over 60 pounds.", whyItMatters: "Income taxation became the primary funding mechanism for modern governments and remains central to debates about wealth, fairness, and state power.", category: "Economics" },
  { month: 1, day: 10, year: 49, title: "Caesar Crosses the Rubicon", description: "Julius Caesar led his legion across the Rubicon River into Italy, defying the Roman Senate and triggering civil war. His famous words 'the die is cast' marked a point of no return.", whyItMatters: "The phrase 'crossing the Rubicon' endures as a metaphor for irreversible decisions, and Caesar's act reshaped the Roman Republic into an Empire.", category: "War" },
  { month: 1, day: 11, year: 1569, title: "First Recorded Lottery in England", description: "The first English state lottery was drawn at St. Paul's Cathedral in London. Queen Elizabeth I established it to raise funds for public works including harbors and fortifications.", whyItMatters: "State lotteries remain a controversial funding mechanism for public services, balancing revenue generation against concerns of regressive taxation.", category: "Economics" },
  { month: 1, day: 12, year: 1519, title: "Death of Emperor Maximilian I", description: "Holy Roman Emperor Maximilian I died, setting off a succession crisis that would see his grandson Charles V elected. Charles would rule an empire on which the sun never set.", whyItMatters: "The Habsburg succession shaped European politics for centuries and illustrates how dynastic power structures created both stability and devastating conflicts.", category: "Politics" },
  { month: 1, day: 13, year: 1610, title: "Galileo Discovers Callisto", description: "Galileo Galilei discovered Callisto, the fourth and final Galilean moon of Jupiter. His systematic observations over several nights proved these were satellites orbiting another planet.", whyItMatters: "The discovery reinforced the revolutionary idea that Earth was not the center of all motion, accelerating the Scientific Revolution.", category: "Science" },
  { month: 1, day: 14, year: 1784, title: "Treaty of Paris Ratified", description: "The Continental Congress ratified the Treaty of Paris, officially ending the American Revolutionary War. Britain formally recognized American independence and ceded territory east of the Mississippi.", whyItMatters: "This treaty established the principle that colonies could successfully achieve independence through revolution, inspiring movements worldwide.", category: "Diplomacy" },
  { month: 1, day: 15, year: 1559, title: "Elizabeth I Crowned Queen", description: "Elizabeth Tudor was crowned Queen of England at Westminster Abbey. Her 45-year reign would become known as the Elizabethan Era, a golden age of English culture, exploration, and power.", whyItMatters: "Elizabeth's reign demonstrated that strong, strategic leadership transcends gender, and her era produced Shakespeare, the defeat of the Armada, and English global expansion.", category: "Politics" },
  { month: 1, day: 16, year: 27, title: "Octavian Becomes Augustus", description: "The Roman Senate granted Octavian the title Augustus, marking the official beginning of the Roman Empire. The transition from Republic to Empire would define Western civilization for centuries.", whyItMatters: "The tension between republican ideals and centralized authority that Augustus embodied remains at the heart of modern political debates.", category: "Politics" },
  { month: 1, day: 17, year: 1773, title: "Captain Cook Crosses Antarctic Circle", description: "Captain James Cook became the first person known to cross the Antarctic Circle during his second voyage of exploration. His expedition proved there was no habitable southern continent.", whyItMatters: "Cook's systematic exploration methods established standards for scientific discovery and expanded humanity's understanding of Earth's geography.", category: "Exploration" },
  { month: 1, day: 18, year: 1778, title: "Cook Discovers Hawaii", description: "Captain James Cook became the first European to reach the Hawaiian Islands, which he named the Sandwich Islands. This contact would profoundly transform Hawaiian civilization.", whyItMatters: "First contact between isolated civilizations illustrates both the promise and peril of globalization, themes still relevant in our interconnected world.", category: "Exploration" },
  { month: 1, day: 19, year: 1736, title: "James Watt Born", description: "James Watt was born in Greenock, Scotland. His improvements to the steam engine would power the Industrial Revolution and transform human civilization from agrarian to industrial.", whyItMatters: "Watt's innovations remind us that incremental improvements to existing technology can be as revolutionary as entirely new inventions.", category: "Technology" },
  { month: 1, day: 20, year: 1265, title: "First English Parliament Convened", description: "Simon de Montfort summoned the first English Parliament to include commoners alongside nobles and clergy. This assembly in Westminster established the principle of representative government.", whyItMatters: "De Montfort's parliament planted the seeds of modern democracy, establishing that governance requires the consent and participation of the governed.", category: "Politics" },
  { month: 1, day: 21, year: 1793, title: "Execution of Louis XVI", description: "King Louis XVI of France was executed by guillotine in Paris. His death marked the definitive end of absolute monarchy in France and sent shockwaves through every royal court in Europe.", whyItMatters: "The execution demonstrated that even the most entrenched institutions can fall when they lose legitimacy, a lesson for all concentrations of power.", category: "Revolution" },
  { month: 1, day: 22, year: 1506, title: "Swiss Guard Established", description: "The first contingent of Swiss Guards arrived at the Vatican to serve as the Pope's personal bodyguards. They have served continuously for over 500 years, making them the oldest active military unit.", whyItMatters: "The Swiss Guard represents how institutional traditions and loyalty create enduring stability across centuries of change.", category: "Culture" },
  { month: 1, day: 23, year: 1556, title: "Deadliest Earthquake in History", description: "The Shaanxi earthquake struck China, killing an estimated 830,000 people. The devastating quake destroyed cave dwellings called yaodongs across a wide area of central China.", whyItMatters: "This catastrophe underscores the importance of disaster preparedness and resilient infrastructure, challenges every civilization must address.", category: "Science" },
  { month: 1, day: 24, year: 41, title: "Caligula Assassinated", description: "Roman Emperor Caligula was assassinated by his own Praetorian Guard after a reign marked by cruelty and instability. The Guard then proclaimed his uncle Claudius as the new emperor.", whyItMatters: "Caligula's downfall illustrates how unchecked power corrupts and how even the most powerful rulers depend on institutional support to govern.", category: "Politics" },
  { month: 1, day: 25, year: 1533, title: "Henry VIII Marries Anne Boleyn", description: "King Henry VIII secretly married Anne Boleyn, an act that would lead to England's break with the Catholic Church and the establishment of the Church of England.", whyItMatters: "Personal decisions by rulers can reshape entire civilizations, and Henry's marriage ultimately led to religious pluralism in the English-speaking world.", category: "Culture" },
  { month: 1, day: 26, year: 1788, title: "First Fleet Arrives in Australia", description: "The First Fleet of British ships arrived at Sydney Cove, marking the beginning of European colonization of Australia. This date is now observed as Australia Day, though it remains controversial.", whyItMatters: "The colonization of Australia raises enduring questions about sovereignty, indigenous rights, and how nations reckon with their founding narratives.", category: "Exploration" },
  { month: 1, day: 27, year: 1756, title: "Mozart Born", description: "Wolfgang Amadeus Mozart was born in Salzburg, Austria. A child prodigy who composed from age five, he would create over 600 works that defined Classical music.", whyItMatters: "Mozart's genius reminds us that nurturing exceptional talent early can produce cultural contributions that enrich humanity for centuries.", category: "Culture" },
  { month: 1, day: 28, year: 814, title: "Death of Charlemagne", description: "Charlemagne, King of the Franks and Emperor of the Romans, died in Aachen. His empire united much of Western Europe for the first time since the fall of Rome.", whyItMatters: "Charlemagne's vision of a unified Europe continues to influence the European Union and debates about continental integration.", category: "Politics" },
  { month: 1, day: 29, year: 1845, title: "The Raven Published", description: "Edgar Allan Poe's poem The Raven was first published in the New York Evening Mirror. The poem's haunting refrain brought Poe immediate fame and established him as a literary icon.", whyItMatters: "Poe pioneered the modern short story and detective fiction, genres that remain dominant in global entertainment and literature.", category: "Culture" },
  { month: 1, day: 30, year: 1649, title: "Execution of Charles I", description: "King Charles I of England was beheaded at Whitehall for high treason. His execution established the revolutionary principle that monarchs are not above the law.", whyItMatters: "The trial and execution of a king established that rulers are accountable to their people, a foundational concept of modern constitutional government.", category: "Revolution" },
  { month: 1, day: 31, year: 1606, title: "Guy Fawkes Executed", description: "Guy Fawkes was executed for his role in the Gunpowder Plot to blow up Parliament. The failed conspiracy has been commemorated every November 5th in Britain ever since.", whyItMatters: "The Gunpowder Plot's legacy endures in discussions of political violence, state surveillance, and the tension between dissent and security.", category: "Politics" },

  // February
  { month: 2, day: 1, year: 1790, title: "First US Supreme Court Session", description: "The Supreme Court of the United States held its first session at the Royal Exchange building in New York City. Chief Justice John Jay presided over what would become the most powerful judiciary in the world.", whyItMatters: "Judicial review, established by the Court, remains the primary mechanism for protecting constitutional rights against government overreach.", category: "Politics" },
  { month: 2, day: 2, year: 1709, title: "Robinson Crusoe Rescued", description: "Alexander Selkirk, the real-life inspiration for Robinson Crusoe, was rescued after four years alone on a Pacific island. His story would inspire Daniel Defoe's novel, considered the first English novel.", whyItMatters: "Selkirk's survival story launched a literary genre exploring human resilience and self-reliance that continues to resonate today.", category: "Culture" },
  { month: 2, day: 3, year: 1468, title: "Gutenberg Dies", description: "Johannes Gutenberg, inventor of the movable-type printing press, died in Mainz, Germany. His invention democratized knowledge and is considered one of the most important innovations in human history.", whyItMatters: "Gutenberg's press enabled the Reformation, the Scientific Revolution, and mass literacy, just as the internet democratizes information today.", category: "Technology" },
  { month: 2, day: 4, year: 211, title: "Septimius Severus Dies at York", description: "Roman Emperor Septimius Severus died at Eboracum (York), England, while campaigning in Britain. His last advice to his sons was to enrich the soldiers and scorn everyone else.", whyItMatters: "Severus's military-first approach to governance foreshadowed the militarization of Roman politics that would eventually contribute to the Empire's decline.", category: "Politics" },
  { month: 2, day: 5, year: 1597, title: "Twenty-Six Martyrs of Japan", description: "Twenty-six Christians were crucified in Nagasaki by order of Toyotomi Hideyoshi. This persecution marked the beginning of Japan's century-long suppression of Christianity.", whyItMatters: "Japan's response to foreign religion illustrates the recurring tension between cultural preservation and globalization that nations face today.", category: "Culture" },
  { month: 2, day: 6, year: 1952, title: "Elizabeth II Becomes Queen", description: "Princess Elizabeth became Queen of the United Kingdom upon the death of her father, King George VI. Her reign would span over 70 years, the longest of any British monarch.", whyItMatters: "Elizabeth II's reign provided institutional stability through decades of dramatic change, demonstrating the value of continuity in governance.", category: "Politics" },
  { month: 2, day: 7, year: 1812, title: "Charles Dickens Born", description: "Charles Dickens was born in Portsmouth, England. His novels exposed the harsh conditions of Victorian England and championed social reform through powerful storytelling.", whyItMatters: "Dickens proved that literature can drive social change, establishing the tradition of using narrative to build empathy and demand justice.", category: "Culture" },
  { month: 2, day: 8, year: 1587, title: "Execution of Mary Queen of Scots", description: "Mary, Queen of Scots was executed at Fotheringhay Castle after 19 years of imprisonment by her cousin Elizabeth I. She was convicted of plotting to assassinate Elizabeth.", whyItMatters: "The execution of a sovereign queen by another raised profound questions about royal authority and political legitimacy that echo in international law today.", category: "Politics" },
  { month: 2, day: 9, year: 1870, title: "US Weather Bureau Established", description: "President Ulysses S. Grant signed a resolution creating a national weather service within the Army Signal Corps. This became the foundation for modern meteorological forecasting.", whyItMatters: "Government investment in weather prediction saves thousands of lives annually and demonstrates the value of publicly funded scientific infrastructure.", category: "Science" },
  { month: 2, day: 10, year: 1258, title: "Fall of Baghdad to the Mongols", description: "The Mongol army under Hulagu Khan sacked Baghdad, ending the Abbasid Caliphate. The destruction of the House of Wisdom and its libraries was one of history's greatest cultural losses.", whyItMatters: "The fall of Baghdad marked the end of the Islamic Golden Age and serves as a stark reminder of how quickly civilizational progress can be destroyed.", category: "War" },
  { month: 2, day: 11, year: 1990, title: "Nelson Mandela Released from Prison", description: "Nelson Mandela walked free after 27 years of imprisonment. His release marked the beginning of the end of apartheid in South Africa and a new era of reconciliation.", whyItMatters: "Mandela's choice of forgiveness over vengeance after decades of injustice remains one of history's most powerful examples of transformative leadership.", category: "Politics" },
  { month: 2, day: 12, year: 1809, title: "Abraham Lincoln Born", description: "Abraham Lincoln was born in a log cabin in Kentucky. He would rise from poverty to become the 16th President and preserve the Union through its greatest crisis.", whyItMatters: "Lincoln's life embodies the democratic ideal that leadership can emerge from any background, and his moral courage during crisis remains a model for leaders.", category: "Politics" },
  { month: 2, day: 13, year: 1633, title: "Galileo Arrives in Rome for Trial", description: "Galileo Galilei arrived in Rome to face the Inquisition for his support of the heliocentric model. His trial would become the defining symbol of the conflict between science and authority.", whyItMatters: "Galileo's persecution remains a cautionary tale about suppressing scientific truth for ideological reasons.", category: "Science" },
  { month: 2, day: 14, year: 269, title: "Saint Valentine Executed", description: "Saint Valentine, a Roman priest, was reportedly executed for performing marriages for soldiers who were forbidden to marry. His martyrdom eventually became associated with romantic love.", whyItMatters: "Valentine's story illustrates how individual acts of conscience against unjust laws can inspire cultural traditions that endure for millennia.", category: "Culture" },
  { month: 2, day: 15, year: 1564, title: "Galileo Galilei Born", description: "Galileo Galilei was born in Pisa, Italy. Called the father of modern science, his observations and experiments laid the groundwork for the scientific method.", whyItMatters: "Galileo established that knowledge must be based on observation and experiment rather than authority, the principle underlying all modern science and technology.", category: "Science" },
  { month: 2, day: 16, year: 1923, title: "Tutankhamun's Tomb Opened", description: "Howard Carter opened the sealed burial chamber of Pharaoh Tutankhamun in the Valley of the Kings. The nearly intact tomb revealed treasures that captivated the entire world.", whyItMatters: "The discovery sparked global fascination with ancient Egypt and demonstrated how archaeology can connect us to civilizations thousands of years old.", category: "Culture" },
  { month: 2, day: 17, year: 1600, title: "Giordano Bruno Burned at the Stake", description: "Italian philosopher Giordano Bruno was burned at the stake in Rome for heresy. Among his ideas was that the universe was infinite and contained many worlds like Earth.", whyItMatters: "Bruno's martyrdom for intellectual freedom symbolizes the ongoing struggle to protect free thought against authoritarianism.", category: "Philosophy" },
  { month: 2, day: 18, year: 1930, title: "Pluto Discovered", description: "Clyde Tombaugh discovered Pluto at Lowell Observatory in Arizona. The distant body was classified as the ninth planet until 2006, when it was reclassified as a dwarf planet.", whyItMatters: "Pluto's story shows that scientific understanding evolves, and that reclassifying knowledge based on new evidence is a strength, not a weakness, of science.", category: "Science" },
  { month: 2, day: 19, year: 1473, title: "Copernicus Born", description: "Nicolaus Copernicus was born in Royal Prussia. His heliocentric model, placing the Sun at the center of the solar system, launched the Scientific Revolution.", whyItMatters: "Copernicus proved that long-held assumptions can be fundamentally wrong, encouraging intellectual courage in challenging established paradigms.", category: "Science" },
  { month: 2, day: 20, year: 1872, title: "Metropolitan Museum of Art Opens", description: "The Metropolitan Museum of Art opened in New York City, beginning its journey to become one of the world's greatest art museums with over two million works.", whyItMatters: "Public art institutions democratize access to cultural heritage, reminding us that preserving creativity enriches all of society.", category: "Culture" },
  { month: 2, day: 21, year: 1848, title: "Communist Manifesto Published", description: "Karl Marx and Friedrich Engels published The Communist Manifesto in London. The pamphlet outlined their theory of class struggle and called for workers to unite.", whyItMatters: "Regardless of one's political views, the Manifesto's analysis of economic inequality and labor relations continues to shape global political discourse.", category: "Philosophy" },
  { month: 2, day: 22, year: 1732, title: "George Washington Born", description: "George Washington was born in Virginia. He would lead the Continental Army to victory, preside over the Constitutional Convention, and serve as the first President of the United States.", whyItMatters: "Washington's voluntary surrender of power after two terms established the democratic tradition of peaceful transfer of authority.", category: "Politics" },
  { month: 2, day: 23, year: 1455, title: "Gutenberg Bible Published", description: "The Gutenberg Bible, the first major book printed with movable type in Europe, was completed in Mainz. About 180 copies were produced, revolutionizing the spread of knowledge.", whyItMatters: "Mass printing democratized literacy and knowledge, directly enabling the Renaissance, Reformation, and modern education systems.", category: "Technology" },
  { month: 2, day: 24, year: 1582, title: "Gregorian Calendar Announced", description: "Pope Gregory XIII issued the papal bull Inter gravissimas, introducing the Gregorian calendar. The reform corrected the drift of the Julian calendar and is the calendar system used worldwide today.", whyItMatters: "The Gregorian calendar's global adoption shows how practical standardization can transcend religious and cultural boundaries.", category: "Science" },
  { month: 2, day: 25, year: 1836, title: "Samuel Colt Patents the Revolver", description: "Samuel Colt received a US patent for the Colt revolver, a firearm with a revolving cylinder containing multiple chambers. This innovation revolutionized personal weaponry.", whyItMatters: "Colt's manufacturing innovations, particularly interchangeable parts, were as influential as the weapon itself, helping launch the American industrial era.", category: "Technology" },
  { month: 2, day: 26, year: 1815, title: "Napoleon Escapes from Elba", description: "Napoleon Bonaparte escaped from exile on the island of Elba and began his march back to Paris. His return would lead to the Hundred Days and the Battle of Waterloo.", whyItMatters: "Napoleon's escape demonstrates how charismatic leadership and popular support can destabilize even the most carefully constructed political settlements.", category: "War" },
  { month: 2, day: 27, year: 1933, title: "Reichstag Fire", description: "The German parliament building was set ablaze in Berlin. The Nazis used the fire as a pretext to suspend civil liberties and consolidate Adolf Hitler's dictatorial power.", whyItMatters: "The Reichstag fire remains a warning about how crises, real or manufactured, can be exploited to dismantle democratic institutions.", category: "Politics" },
  { month: 2, day: 28, year: 1953, title: "Watson and Crick Discover DNA Structure", description: "James Watson and Francis Crick determined the double-helix structure of DNA at Cambridge University. This discovery unlocked the molecular basis of heredity and life itself.", whyItMatters: "Understanding DNA's structure enabled modern genetics, medicine, forensics, and biotechnology, fundamentally changing what humans can achieve.", category: "Science" },
  { month: 2, day: 29, year: 1504, title: "Columbus Uses Lunar Eclipse", description: "Christopher Columbus used his knowledge of an upcoming lunar eclipse to convince Jamaican natives to continue providing his stranded crew with supplies, claiming he could make the moon disappear.", whyItMatters: "This episode illustrates both the power of scientific knowledge and the ethical questions around using that power to manipulate others.", category: "Exploration" },

  // March
  { month: 3, day: 1, year: 1872, title: "Yellowstone Becomes First National Park", description: "President Ulysses S. Grant signed the Yellowstone National Park Protection Act, creating the world's first national park. The act preserved 2.2 million acres of wilderness for public enjoyment.", whyItMatters: "The national park concept has been adopted worldwide, establishing the principle that natural wonders belong to all people, not private interests.", category: "Politics" },
  { month: 3, day: 2, year: 1836, title: "Texas Declares Independence", description: "Texan delegates declared independence from Mexico at Washington-on-the-Brazos. The Republic of Texas would exist for nearly a decade before joining the United States.", whyItMatters: "Texas independence demonstrates how cultural identity and self-determination drive political movements, themes still active in separatist movements globally.", category: "Revolution" },
  { month: 3, day: 3, year: 1847, title: "Alexander Graham Bell Born", description: "Alexander Graham Bell was born in Edinburgh, Scotland. His invention of the telephone in 1876 would revolutionize human communication and lay the foundation for the modern connected world.", whyItMatters: "Bell's work on voice transmission launched the telecommunications revolution that evolved into today's global internet and mobile networks.", category: "Technology" },
  { month: 3, day: 4, year: 1789, title: "US Constitution Takes Effect", description: "The United States Constitution officially took effect as the first Congress convened in New York City. The document established the framework for American governance that endures today.", whyItMatters: "The Constitution's system of checks and balances has been a model for democracies worldwide and continues to shape debates about governance.", category: "Politics" },
  { month: 3, day: 5, year: 1770, title: "Boston Massacre", description: "British soldiers killed five colonists in Boston, an event that became a rallying cry for American independence. Paul Revere's engraving of the scene became powerful propaganda.", whyItMatters: "The Boston Massacre shows how a single violent incident, amplified by media, can catalyze revolutionary movements.", category: "Revolution" },
  { month: 3, day: 6, year: 1475, title: "Michelangelo Born", description: "Michelangelo di Lodovico Buonarroti was born in Caprese, Italy. He would become one of the greatest artists in history, creating the Sistine Chapel ceiling and the sculpture David.", whyItMatters: "Michelangelo's mastery across painting, sculpture, and architecture demonstrates that investing in artistic excellence creates cultural treasures that inspire for centuries.", category: "Culture" },
  { month: 3, day: 7, year: 322, title: "Aristotle Dies", description: "The Greek philosopher Aristotle died in Chalcis. His works on logic, metaphysics, ethics, politics, and natural science formed the intellectual foundation of Western civilization for nearly two millennia.", whyItMatters: "Aristotle's systematic approach to knowledge created the framework for scientific inquiry, political theory, and ethical reasoning still used today.", category: "Philosophy" },
  { month: 3, day: 8, year: 1917, title: "February Revolution Begins in Russia", description: "Protests erupted in Petrograd marking the start of the Russian Revolution. Within days, Tsar Nicholas II abdicated, ending three centuries of Romanov rule.", whyItMatters: "The Russian Revolution demonstrated how widespread inequality and government unresponsiveness can lead to rapid, radical systemic change.", category: "Revolution" },
  { month: 3, day: 9, year: 1796, title: "Napoleon Marries Josephine", description: "Napoleon Bonaparte married Josephine de Beauharnais in a civil ceremony in Paris. Their complex relationship would intertwine with the fate of empires across Europe.", whyItMatters: "Napoleon and Josephine's relationship shows how personal dynamics can influence political decisions at the highest levels of power.", category: "Culture" },
  { month: 3, day: 10, year: 241, title: "Battle of the Aegates", description: "Rome defeated Carthage at the Battle of the Aegates, ending the First Punic War. Rome's naval victory established it as the dominant Mediterranean power.", whyItMatters: "Rome's willingness to build an entire navy from scratch to match Carthage shows how adaptability and determination can overcome established advantages.", category: "War" },
  { month: 3, day: 11, year: 1851, title: "Verdi's Rigoletto Premieres", description: "Giuseppe Verdi's opera Rigoletto premiered at La Fenice in Venice to immediate acclaim. The opera's exploration of power, corruption, and vengeance resonated deeply with audiences.", whyItMatters: "Verdi's operas channeled political aspirations for Italian unification, showing how art can serve as a vehicle for social and political change.", category: "Culture" },
  { month: 3, day: 12, year: 1613, title: "Romanov Dynasty Begins", description: "Michael Romanov was elected Tsar of Russia, founding the Romanov dynasty that would rule for over 300 years. The dynasty transformed Russia from a regional power into a global empire.", whyItMatters: "The Romanov rise and eventual fall in 1917 illustrates how dynasties must adapt to survive, and that legitimacy requires more than hereditary claims.", category: "Politics" },
  { month: 3, day: 13, year: 1781, title: "William Herschel Discovers Uranus", description: "William Herschel discovered the planet Uranus, the first planet found since antiquity. His discovery doubled the known size of the solar system.", whyItMatters: "Herschel's discovery, made with a homemade telescope, shows that breakthrough discoveries can come from dedicated amateur scientists.", category: "Science" },
  { month: 3, day: 14, year: 1879, title: "Albert Einstein Born", description: "Albert Einstein was born in Ulm, Germany. His theories of relativity revolutionized physics, and his equation E=mc2 became the most famous equation in history.", whyItMatters: "Einstein's work reshaped our understanding of space, time, and energy, enabling technologies from GPS to nuclear power.", category: "Science" },
  { month: 3, day: 15, year: 44, title: "Assassination of Julius Caesar", description: "Julius Caesar was assassinated by a group of senators on the Ides of March in Rome. The conspirators, including Brutus, believed they were saving the Republic, but instead triggered its final collapse.", whyItMatters: "Caesar's assassination shows that political violence often produces the opposite of its intended outcome, a lesson repeated throughout history.", category: "Politics" },
  { month: 3, day: 16, year: 1802, title: "West Point Founded", description: "The United States Military Academy at West Point was established by an act of Congress. The academy has trained leaders including Grant, Lee, Eisenhower, and MacArthur.", whyItMatters: "West Point's emphasis on duty, honor, and country illustrates the importance of professional military education in maintaining civilian-controlled armed forces.", category: "Politics" },
  { month: 3, day: 17, year: 461, title: "Death of Saint Patrick", description: "Saint Patrick, the patron saint of Ireland, died. A former slave who returned to Ireland as a missionary, he became one of the most celebrated figures in Irish and Christian history.", whyItMatters: "Patrick's transformation from enslaved person to cultural icon demonstrates how personal adversity can fuel a mission that shapes an entire civilization.", category: "Culture" },
  { month: 3, day: 18, year: 1314, title: "Jacques de Molay Burned at the Stake", description: "The last Grand Master of the Knights Templar was burned at the stake in Paris by order of King Philip IV. Legend says de Molay cursed both the king and pope from the flames.", whyItMatters: "The destruction of the Templars illustrates how powerful institutions can be dismantled when their wealth threatens those in power.", category: "Politics" },
  { month: 3, day: 19, year: 1474, title: "Venice Enacts First Patent Law", description: "The Venetian Republic passed the world's first codified patent law, granting inventors exclusive rights to their creations for ten years. This established the legal framework for intellectual property.", whyItMatters: "Patent law remains essential to innovation economics, balancing incentives for inventors with public access to knowledge.", category: "Economics" },
  { month: 3, day: 20, year: 1815, title: "Napoleon Returns to Paris", description: "Napoleon entered Paris in triumph after his escape from Elba, beginning the Hundred Days. Soldiers sent to arrest him instead rallied to his cause.", whyItMatters: "Napoleon's return demonstrates the extraordinary power of personal charisma and loyalty in politics, and how quickly political situations can reverse.", category: "War" },
  { month: 3, day: 21, year: 1685, title: "Johann Sebastian Bach Born", description: "Johann Sebastian Bach was born in Eisenach, Germany. His compositions, from the Brandenburg Concertos to the Mass in B Minor, represent the pinnacle of Baroque music.", whyItMatters: "Bach's mathematical precision and emotional depth in music continue to influence composers across all genres, from classical to electronic.", category: "Culture" },
  { month: 3, day: 22, year: 1765, title: "Stamp Act Passed", description: "The British Parliament passed the Stamp Act, imposing the first direct tax on the American colonies. The resulting protests established the principle of no taxation without representation.", whyItMatters: "The Stamp Act crisis established the foundational democratic principle that citizens must consent to taxation through their representatives.", category: "Revolution" },
  { month: 3, day: 23, year: 1775, title: "Patrick Henry's 'Liberty or Death' Speech", description: "Patrick Henry delivered his famous speech to the Virginia Convention, declaring 'Give me liberty, or give me death!' His words galvanized support for American independence.", whyItMatters: "Henry's speech demonstrates the power of rhetoric to inspire action and reminds us that freedom often requires the courage to demand it.", category: "Revolution" },
  { month: 3, day: 24, year: 1603, title: "Union of English and Scottish Crowns", description: "James VI of Scotland became James I of England upon Elizabeth I's death, uniting the English and Scottish crowns. This personal union eventually led to the creation of Great Britain.", whyItMatters: "The union of crowns shows how peaceful political integration can occur through dynastic succession, offering alternatives to conquest.", category: "Politics" },
  { month: 3, day: 25, year: 1821, title: "Greek War of Independence Begins", description: "Greek revolutionaries raised the flag of revolt against the Ottoman Empire, beginning a war of independence that would inspire nationalist movements across Europe.", whyItMatters: "The Greek revolution demonstrated that ancient cultural identity could fuel modern political movements, inspiring independence struggles worldwide.", category: "Revolution" },
  { month: 3, day: 26, year: 1827, title: "Beethoven Dies", description: "Ludwig van Beethoven died in Vienna at age 56. Despite losing his hearing, he composed some of the most powerful music ever written, including the Ninth Symphony.", whyItMatters: "Beethoven's triumph over deafness to create masterworks remains one of history's greatest examples of perseverance in the face of adversity.", category: "Culture" },
  { month: 3, day: 27, year: 1513, title: "Ponce de Leon Reaches Florida", description: "Spanish explorer Juan Ponce de Leon became the first known European to reach Florida. He named it La Florida for the Easter season and its lush vegetation.", whyItMatters: "European arrival in Florida began centuries of cultural transformation in North America, illustrating the far-reaching consequences of exploration.", category: "Exploration" },
  { month: 3, day: 28, year: 1854, title: "Crimean War Begins for Britain and France", description: "Britain and France declared war on Russia, formally entering the Crimean War. The conflict would introduce modern warfare, war journalism, and military nursing.", whyItMatters: "The Crimean War produced Florence Nightingale's nursing revolution and the first war photography, changing how societies perceive and respond to conflict.", category: "War" },
  { month: 3, day: 29, year: 1461, title: "Battle of Towton", description: "The Battle of Towton in Yorkshire was the bloodiest battle ever fought on English soil, with an estimated 28,000 casualties. It was a decisive Yorkist victory in the Wars of the Roses.", whyItMatters: "Towton's devastation illustrates how civil wars inflict the deepest wounds on nations, a pattern repeated across centuries and continents.", category: "War" },
  { month: 3, day: 30, year: 1867, title: "United States Purchases Alaska", description: "Secretary of State William Seward agreed to purchase Alaska from Russia for $7.2 million, roughly two cents per acre. Initially mocked as Seward's Folly, the purchase proved enormously valuable.", whyItMatters: "Alaska's purchase reminds us that bold, unpopular decisions can prove visionary, and that national resources require long-term strategic thinking.", category: "Diplomacy" },
  { month: 3, day: 31, year: 1889, title: "Eiffel Tower Completed", description: "The Eiffel Tower was completed in Paris after two years of construction. Built for the 1889 World's Fair, the iron tower was initially controversial but became France's most iconic symbol.", whyItMatters: "The Eiffel Tower shows how innovative engineering, even when initially criticized, can become enduring symbols of national identity and human achievement.", category: "Technology" },

  // April
  { month: 4, day: 1, year: 1789, title: "First Speaker of the US House Elected", description: "Frederick Muhlenberg was elected as the first Speaker of the United States House of Representatives. The role would become one of the most powerful positions in American government.", whyItMatters: "The Speaker's role in managing legislative business and succession to the presidency shows how procedural positions can accumulate enormous power.", category: "Politics" },
  { month: 4, day: 2, year: 1513, title: "Ponce de Leon Claims Florida for Spain", description: "Juan Ponce de Leon officially claimed La Florida for Spain. His exploration established Spain's presence in what would become the southeastern United States.", whyItMatters: "European claims on the Americas set in motion centuries of colonization whose effects on indigenous peoples and global power dynamics persist today.", category: "Exploration" },
  { month: 4, day: 3, year: 1860, title: "Pony Express Begins", description: "The Pony Express began its mail delivery service between St. Joseph, Missouri and Sacramento, California. Riders covered 1,900 miles in about 10 days.", whyItMatters: "The Pony Express, though short-lived, symbolizes American frontier innovation and the enduring human desire for faster communication.", category: "Technology" },
  { month: 4, day: 4, year: 1818, title: "US Flag Design Established", description: "Congress adopted a flag with 13 stripes and a star for each state. This flexible design allowed the flag to grow with the nation, adding a star for each new state.", whyItMatters: "The evolving flag design embodied the idea of an expandable union, an innovative concept in national identity and governance.", category: "Politics" },
  { month: 4, day: 5, year: 1614, title: "Pocahontas Marries John Rolfe", description: "Pocahontas married English tobacco planter John Rolfe at Jamestown, Virginia. Their marriage created a period of peace between the Powhatan Confederacy and the English colonists.", whyItMatters: "This intercultural alliance illustrates both the potential for cross-cultural understanding and the complexities of colonial power dynamics.", category: "Diplomacy" },
  { month: 4, day: 6, year: 1199, title: "Richard the Lionheart Dies", description: "King Richard I of England died from a crossbow wound received during a siege in France. Despite spending only six months of his reign in England, he became a legendary figure.", whyItMatters: "Richard's legendary status despite his absence from England shows how military valor and narrative can create leadership myths that outlast reality.", category: "War" },
  { month: 4, day: 7, year: 30, title: "Jesus of Nazareth Crucified", description: "According to most historical estimates, Jesus of Nazareth was crucified in Jerusalem under Pontius Pilate around this date. His teachings would form the foundation of Christianity.", whyItMatters: "Regardless of religious belief, the historical impact of Jesus's teachings on law, ethics, art, and culture has shaped Western civilization more than any other single figure.", category: "Culture" },
  { month: 4, day: 8, year: 1820, title: "Venus de Milo Discovered", description: "A Greek farmer discovered the ancient statue of Aphrodite, known as the Venus de Milo, on the island of Milos. The sculpture became one of the most famous artworks in history.", whyItMatters: "The Venus de Milo reminds us that artistic masterpieces can resurface after millennia, and that beauty and craftsmanship transcend time.", category: "Culture" },
  { month: 4, day: 9, year: 1865, title: "Lee Surrenders at Appomattox", description: "Confederate General Robert E. Lee surrendered to Union General Ulysses S. Grant at Appomattox Court House, effectively ending the American Civil War after four years of devastating conflict.", whyItMatters: "Grant's generous surrender terms helped begin reconciliation, demonstrating that how wars end matters as much as how they are won.", category: "War" },
  { month: 4, day: 10, year: 1790, title: "US Patent System Created", description: "President Washington signed the first US Patent Act, establishing a system to protect inventors' rights. The law encouraged innovation by guaranteeing exclusive rights to new inventions.", whyItMatters: "The patent system has driven centuries of innovation by ensuring inventors can profit from their creativity, though debates about its scope continue.", category: "Economics" },
  { month: 4, day: 11, year: 1689, title: "William and Mary Crowned", description: "William III and Mary II were crowned joint monarchs of England after the Glorious Revolution. Their acceptance of the Bill of Rights established constitutional monarchy.", whyItMatters: "The Glorious Revolution established that monarchs rule by consent and are bound by law, principles fundamental to modern constitutional government.", category: "Politics" },
  { month: 4, day: 12, year: 1204, title: "Fourth Crusade Sacks Constantinople", description: "Crusaders sacked Constantinople, the capital of the Byzantine Empire, in one of history's greatest acts of betrayal. Christian knights plundered the greatest Christian city.", whyItMatters: "The sack of Constantinople reveals how stated ideals can mask greed and ambition, and how internal divisions weaken civilizations more than external threats.", category: "War" },
  { month: 4, day: 13, year: 1743, title: "Thomas Jefferson Born", description: "Thomas Jefferson was born in Virginia. Author of the Declaration of Independence and third President, he championed individual liberty, religious freedom, and public education.", whyItMatters: "Jefferson's articulation of natural rights and democratic governance continues to influence constitutions and human rights declarations worldwide.", category: "Politics" },
  { month: 4, day: 14, year: 1865, title: "Abraham Lincoln Assassinated", description: "President Abraham Lincoln was shot by John Wilkes Booth at Ford's Theatre in Washington. He died the following morning, making him a martyr for the cause of union and freedom.", whyItMatters: "Lincoln's assassination demonstrated that political violence cannot destroy ideas, and his legacy of preserving democracy grew stronger after his death.", category: "Politics" },
  { month: 4, day: 15, year: 1452, title: "Leonardo da Vinci Born", description: "Leonardo da Vinci was born in Vinci, Italy. The ultimate Renaissance man, he excelled in painting, sculpture, engineering, anatomy, and countless other fields.", whyItMatters: "Leonardo's boundless curiosity and interdisciplinary approach remain the ideal model for innovation, showing that the greatest breakthroughs come from connecting diverse fields.", category: "Culture" },
  { month: 4, day: 16, year: 1746, title: "Battle of Culloden", description: "British forces defeated the Jacobite army at Culloden, the last pitched battle fought on British soil. The defeat ended the Stuart claim to the British throne and devastated Highland culture.", whyItMatters: "Culloden shows how military defeat can destroy an entire way of life, and how cultural suppression following conflict can have lasting consequences.", category: "War" },
  { month: 4, day: 17, year: 1397, title: "Geoffrey Chaucer Recites Canterbury Tales", description: "Geoffrey Chaucer reportedly first recited The Canterbury Tales at the court of Richard II. The work established English as a legitimate literary language alongside French and Latin.", whyItMatters: "Chaucer proved that vernacular languages could produce great literature, democratizing storytelling and cultural expression.", category: "Culture" },
  { month: 4, day: 18, year: 1775, title: "Paul Revere's Ride", description: "Paul Revere rode through the Massachusetts countryside warning colonists that British troops were approaching. His ride became a symbol of American patriotic vigilance.", whyItMatters: "Revere's ride demonstrates how rapid communication and community networks can mobilize resistance, a principle as relevant in the digital age as in 1775.", category: "Revolution" },
  { month: 4, day: 19, year: 1775, title: "Battles of Lexington and Concord", description: "The first shots of the American Revolution were fired at Lexington and Concord. These skirmishes marked the point where political dispute transformed into armed conflict.", whyItMatters: "The 'shot heard round the world' established that ordinary citizens could challenge the world's greatest military power, inspiring democratic revolutions globally.", category: "Revolution" },
  { month: 4, day: 20, year: 1862, title: "Pasteurization Completed", description: "Louis Pasteur and Claude Bernard completed the first test of pasteurization, proving that heating liquids could kill harmful microorganisms. This discovery saved countless lives.", whyItMatters: "Pasteurization revolutionized food safety and demonstrated that scientific innovation can produce practical solutions to everyday public health challenges.", category: "Science" },
  { month: 4, day: 21, year: 753, title: "Traditional Founding of Rome", description: "According to Roman tradition, Romulus founded the city of Rome on this date. The legendary founding established the mythology that would shape Roman identity for over a millennium.", whyItMatters: "Rome's founding myths illustrate how narratives of origin shape national identity, a pattern seen in every civilization from ancient to modern.", category: "Culture" },
  { month: 4, day: 22, year: 1500, title: "Pedro Cabral Reaches Brazil", description: "Portuguese navigator Pedro Alvares Cabral became the first European to reach Brazil. His landing began Portugal's colonization of South America's largest country.", whyItMatters: "Cabral's arrival set Brazil on a distinct colonial path from Spanish America, creating the cultural and linguistic diversity of Latin America.", category: "Exploration" },
  { month: 4, day: 23, year: 1616, title: "Shakespeare Dies", description: "William Shakespeare died in Stratford-upon-Avon at age 52. His 37 plays and 154 sonnets have been translated into every major language and continue to be performed worldwide.", whyItMatters: "Shakespeare's exploration of human nature, power, love, and mortality remains unmatched, proving that great art transcends time and culture.", category: "Culture" },
  { month: 4, day: 24, year: 1184, title: "Traditional Date of the Fall of Troy", description: "According to ancient tradition, the city of Troy fell to the Greeks on this date after a ten-year siege. The Trojan War became the foundational narrative of Western literature.", whyItMatters: "The Trojan War stories, from Homer's Iliad to Virgil's Aeneid, established themes of heroism, fate, and conflict that still define Western storytelling.", category: "War" },
  { month: 4, day: 25, year: 1507, title: "America Gets Its Name", description: "German cartographer Martin Waldseemuller published a world map naming the New World 'America' after explorer Amerigo Vespucci, who recognized it as a separate continent.", whyItMatters: "The naming of America shows how cartography and publication shape our understanding of the world, and how historical credit can be somewhat arbitrary.", category: "Exploration" },
  { month: 4, day: 26, year: 121, title: "Marcus Aurelius Born", description: "Future Roman Emperor Marcus Aurelius was born in Rome. He would become both the most powerful man in the world and one of history's most influential philosophers.", whyItMatters: "Marcus Aurelius proved that power and wisdom need not be contradictory, and his Meditations remain essential reading for leaders seeking to govern with integrity.", category: "Philosophy" },
  { month: 4, day: 27, year: 4977, title: "Traditional Date of Creation (Archbishop Ussher)", description: "According to Archbishop James Ussher's 17th-century calculation, the world was created on this date in 4004 BC. Though scientifically outdated, his work represented a serious scholarly effort.", whyItMatters: "Ussher's chronology shows how each era interprets evidence through its own lens, and how scientific understanding progressively refines our knowledge.", category: "Science" },
  { month: 4, day: 28, year: 1789, title: "Mutiny on the Bounty", description: "Fletcher Christian led a mutiny against Captain William Bligh aboard HMS Bounty in the Pacific Ocean. Bligh and loyal crew members were set adrift in a small boat.", whyItMatters: "The Bounty mutiny raises enduring questions about leadership, authority, and the limits of obedience that remain relevant in organizations today.", category: "Exploration" },
  { month: 4, day: 29, year: 1429, title: "Joan of Arc Enters Orleans", description: "Joan of Arc arrived at the besieged city of Orleans with supplies and reinforcements. Her arrival and subsequent victory turned the tide of the Hundred Years' War in France's favor.", whyItMatters: "Joan's triumph at Orleans demonstrates how inspirational leadership and conviction can reverse seemingly hopeless situations.", category: "War" },
  { month: 4, day: 30, year: 311, title: "Edict of Toleration Issued", description: "Roman Emperor Galerius issued the Edict of Toleration, officially ending the persecution of Christians in the Roman Empire. This paved the way for Christianity to become the dominant religion.", whyItMatters: "The Edict established the principle of religious toleration, a concept that would take centuries to fully develop but remains central to modern pluralistic societies.", category: "Politics" },

  // May
  { month: 5, day: 1, year: 1776, title: "Illuminati Founded", description: "Adam Weishaupt founded the Order of the Illuminati in Bavaria. The secret society promoted Enlightenment ideals of reason, secularism, and free thought against religious influence.", whyItMatters: "The Illuminati's brief existence and outsized cultural legacy show how secretive organizations capture public imagination and fuel conspiracy theories for centuries.", category: "Philosophy" },
  { month: 5, day: 2, year: 1519, title: "Leonardo da Vinci Dies", description: "Leonardo da Vinci died at Amboise, France, at age 67. He left behind notebooks containing thousands of pages of observations, inventions, and artistic studies.", whyItMatters: "Leonardo's notebooks, unpublished for centuries, remind us that preserving knowledge and making it accessible is essential for advancing civilization.", category: "Culture" },
  { month: 5, day: 3, year: 1469, title: "Machiavelli Born", description: "Niccolo Machiavelli was born in Florence. His work The Prince became the foundational text of modern political science and the study of power.", whyItMatters: "Machiavelli's realistic analysis of power dynamics remains essential reading for anyone who wants to understand how politics actually works.", category: "Philosophy" },
  { month: 5, day: 4, year: 1494, title: "Columbus Reaches Jamaica", description: "Christopher Columbus first arrived in Jamaica during his second voyage to the Americas. He claimed the island for Spain, beginning European influence in the Caribbean.", whyItMatters: "Columbus's Caribbean explorations launched the Age of Colonization, whose effects on indigenous populations and global trade networks persist today.", category: "Exploration" },
  { month: 5, day: 5, year: 1821, title: "Napoleon Dies on St. Helena", description: "Napoleon Bonaparte died in exile on the island of Saint Helena at age 51. His legacy reshaped European borders, legal systems, and military strategy.", whyItMatters: "Napoleon's Napoleonic Code remains the basis of civil law in many countries, showing how a single leader's reforms can outlast their political power.", category: "Politics" },
  { month: 5, day: 6, year: 1527, title: "Sack of Rome", description: "Troops of Holy Roman Emperor Charles V sacked Rome, ending the Renaissance in the Eternal City. The devastation marked a turning point in European power politics.", whyItMatters: "The Sack of Rome demonstrated that even the most culturally rich cities are vulnerable to political and military upheaval.", category: "War" },
  { month: 5, day: 7, year: 1824, title: "Beethoven's Ninth Symphony Premieres", description: "Beethoven's Ninth Symphony premiered in Vienna. Completely deaf by this time, Beethoven had to be turned around to see the audience's thunderous applause.", whyItMatters: "The Ninth Symphony's Ode to Joy has become a universal anthem for human brotherhood, adopted by the European Union as its official anthem.", category: "Culture" },
  { month: 5, day: 8, year: 1886, title: "Coca-Cola Invented", description: "Pharmacist John Pemberton first served Coca-Cola at Jacobs' Pharmacy in Atlanta, Georgia. The drink would become the world's most recognized brand.", whyItMatters: "Coca-Cola's global reach illustrates how American consumer culture spread worldwide in the 20th century, for better and worse.", category: "Economics" },
  { month: 5, day: 9, year: 1502, title: "Columbus Begins Final Voyage", description: "Christopher Columbus departed on his fourth and final voyage to the Americas. This journey would take him along Central America's coast in search of a passage to Asia.", whyItMatters: "Columbus's persistent search for a western route to Asia shows how incorrect assumptions can still lead to transformative discoveries.", category: "Exploration" },
  { month: 5, day: 10, year: 1869, title: "Transcontinental Railroad Completed", description: "The golden spike was driven at Promontory Summit, Utah, completing the first transcontinental railroad. The railroad connected the Atlantic and Pacific coasts of the United States.", whyItMatters: "The transcontinental railroad transformed America from a collection of regions into a unified continental economy, demonstrating infrastructure's power to reshape nations.", category: "Technology" },
  { month: 5, day: 11, year: 330, title: "Constantinople Dedicated", description: "Emperor Constantine I dedicated Constantinople as the new capital of the Roman Empire. The city would serve as the capital of the Byzantine Empire for over a thousand years.", whyItMatters: "Constantinople's strategic location made it the hinge between East and West for a millennium, and its legacy lives on in modern Istanbul.", category: "Politics" },
  { month: 5, day: 12, year: 1820, title: "Florence Nightingale Born", description: "Florence Nightingale was born in Florence, Italy. Her pioneering work in nursing during the Crimean War transformed healthcare and established nursing as a respected profession.", whyItMatters: "Nightingale's use of statistical analysis to improve medical care pioneered evidence-based medicine, the standard for healthcare decisions today.", category: "Science" },
  { month: 5, day: 13, year: 1846, title: "US Declares War on Mexico", description: "The United States formally declared war on Mexico, beginning the Mexican-American War. The conflict would result in Mexico ceding nearly half its territory to the US.", whyItMatters: "The Mexican-American War shaped the modern map of North America and intensified the slavery debate that led to the American Civil War.", category: "War" },
  { month: 5, day: 14, year: 1796, title: "Jenner Administers First Vaccine", description: "Edward Jenner inoculated eight-year-old James Phipps with cowpox material, creating the first successful vaccine. This experiment would eventually lead to the eradication of smallpox.", whyItMatters: "Vaccination has saved more lives than any other medical innovation, and Jenner's work laid the foundation for modern immunology.", category: "Science" },
  { month: 5, day: 15, year: 1718, title: "First Machine Gun Patented", description: "James Puckle patented the Puckle Gun, considered the first machine gun. Though it saw limited use, it foreshadowed the mechanization of warfare.", whyItMatters: "The mechanization of weapons fundamentally changed the nature of conflict, raising ethical questions about technology's role in warfare that persist today.", category: "Technology" },
  { month: 5, day: 16, year: 1770, title: "Marie Antoinette Marries Louis XVI", description: "Austrian Archduchess Marie Antoinette married the French Dauphin Louis XVI at Versailles. Their marriage alliance would end in revolution, imprisonment, and execution.", whyItMatters: "Marie Antoinette's fate illustrates how public perception and inequality can destroy even the most privileged, a warning for elites in every era.", category: "Politics" },
  { month: 5, day: 17, year: 1792, title: "New York Stock Exchange Founded", description: "Twenty-four stockbrokers signed the Buttonwood Agreement under a tree on Wall Street, founding what would become the New York Stock Exchange.", whyItMatters: "The NYSE became the center of global capitalism, and its history reflects both the power and volatility of market-based economic systems.", category: "Economics" },
  { month: 5, day: 18, year: 1804, title: "Napoleon Proclaimed Emperor", description: "Napoleon Bonaparte was proclaimed Emperor of the French by the Senate. His coronation ceremony later that year saw him crown himself, symbolizing that his power came from his own achievements.", whyItMatters: "Napoleon's self-coronation challenged the divine right of kings, asserting that leadership should be earned through merit rather than birth.", category: "Politics" },
  { month: 5, day: 19, year: 1536, title: "Anne Boleyn Executed", description: "Queen Anne Boleyn was executed at the Tower of London on charges of treason, adultery, and witchcraft. Her daughter Elizabeth would later become England's greatest monarch.", whyItMatters: "Anne's execution shows how power can be wielded arbitrarily, but also how her legacy through Elizabeth ultimately transformed England.", category: "Politics" },
  { month: 5, day: 20, year: 325, title: "First Council of Nicaea Opens", description: "Emperor Constantine convened the First Council of Nicaea, the first ecumenical council of the Christian Church. The council established key Christian doctrines including the Nicene Creed.", whyItMatters: "Nicaea showed how religious institutions formalize beliefs, and the process of reaching consensus through council remains relevant in governance.", category: "Culture" },
  { month: 5, day: 21, year: 1471, title: "Albrecht Durer Born", description: "Albrecht Durer was born in Nuremberg, Germany. He became the greatest artist of the Northern Renaissance, mastering painting, printmaking, and theoretical writing on art.", whyItMatters: "Durer's printmaking democratized art by making high-quality images reproducible, foreshadowing the mass media revolution.", category: "Culture" },
  { month: 5, day: 22, year: 334, title: "Battle of the Granicus", description: "Alexander the Great won his first major battle against the Persian Empire at the Granicus River. This victory opened Asia Minor to Macedonian conquest.", whyItMatters: "Alexander's bold river crossing demonstrates how decisive action and calculated risk-taking can overcome numerically superior opponents.", category: "War" },
  { month: 5, day: 23, year: 1618, title: "Defenestration of Prague", description: "Protestant nobles threw two Catholic governors from a window of Prague Castle, triggering the Thirty Years' War, the deadliest European conflict before World War I.", whyItMatters: "The Defenestration shows how a single provocative act can trigger cascading conflicts, a pattern seen repeatedly in history.", category: "War" },
  { month: 5, day: 24, year: 1543, title: "Copernicus Dies", description: "Nicolaus Copernicus died in Frombork, Poland, on the same day his revolutionary book De Revolutionibus was published. He may have held the first printed copy on his deathbed.", whyItMatters: "Copernicus's heliocentric theory showed that accepted wisdom can be fundamentally wrong, encouraging future generations to question established beliefs.", category: "Science" },
  { month: 5, day: 25, year: 585, title: "Thales Predicts Solar Eclipse", description: "Thales of Miletus reportedly predicted a solar eclipse that halted a battle between the Lydians and Medes. This is considered the first known scientific prediction in Western history.", whyItMatters: "Thales's prediction demonstrated that natural phenomena follow predictable laws, the foundational insight of all scientific endeavor.", category: "Science" },
  { month: 5, day: 26, year: 1805, title: "Napoleon Crowned King of Italy", description: "Napoleon Bonaparte crowned himself King of Italy in Milan Cathedral, placing the Iron Crown of Lombardy on his own head. His Italian kingdom reshaped the peninsula's political landscape.", whyItMatters: "Napoleon's Italian reforms, including legal codes and administrative modernization, planted seeds for Italian unification decades later.", category: "Politics" },
  { month: 5, day: 27, year: 1703, title: "Saint Petersburg Founded", description: "Tsar Peter the Great founded Saint Petersburg as Russia's new capital. The city symbolized his vision of a modern, Western-oriented Russia and became one of Europe's greatest cities.", whyItMatters: "Peter's creation of a new capital from nothing demonstrates how visionary leadership can reshape a nation's identity and trajectory.", category: "Politics" },
  { month: 5, day: 28, year: 585, title: "Eclipse Ends Battle of Halys", description: "A solar eclipse occurred during the Battle of the Halys between the Lydians and Medes. Both armies interpreted it as a divine sign and agreed to peace.", whyItMatters: "This event illustrates how natural phenomena have been interpreted through cultural lenses throughout history, influencing major political decisions.", category: "War" },
  { month: 5, day: 29, year: 1453, title: "Fall of Constantinople", description: "Ottoman Sultan Mehmed II conquered Constantinople, ending the Byzantine Empire after over 1,000 years. The fall marked the definitive end of the Roman Empire.", whyItMatters: "The fall of Constantinople reshaped trade routes, drove European exploration westward, and marks a traditional boundary between the Medieval and Modern eras.", category: "War" },
  { month: 5, day: 30, year: 1431, title: "Joan of Arc Burned at the Stake", description: "Joan of Arc was burned at the stake in Rouen at age 19. Convicted of heresy by an English-allied court, she was later declared a saint by the Catholic Church.", whyItMatters: "Joan's execution and later vindication demonstrate how political justice can be reversed by history, and how moral courage transcends temporal power.", category: "War" },
  { month: 5, day: 31, year: 1859, title: "Big Ben Rings for the First Time", description: "The Great Bell of the clock tower at the Palace of Westminster, known as Big Ben, rang for the first time. It has marked the hours for Parliament and London ever since.", whyItMatters: "Big Ben symbolizes the endurance of democratic institutions, and its chimes during wartime broadcasts became a sound of resilience.", category: "Culture" },

  // June
  { month: 6, day: 1, year: 1495, title: "First Written Record of Scotch Whisky", description: "Friar John Cor recorded the first known written reference to Scotch whisky in the Scottish Exchequer Rolls. The entry mentions eight bolls of malt used to make aqua vitae.", whyItMatters: "The regulation and taxation of spirits has been a significant source of government revenue and social policy debate for over five centuries.", category: "Economics" },
  { month: 6, day: 2, year: 455, title: "Vandals Sack Rome", description: "The Vandals under King Genseric entered Rome and plundered the city for fourteen days. The sack gave the English language the word vandalism.", whyItMatters: "The Vandal sack of Rome illustrates how civilizations weaken from within before falling to external threats, a pattern repeated throughout history.", category: "War" },
  { month: 6, day: 3, year: 1769, title: "Transit of Venus Observed", description: "Captain James Cook observed the Transit of Venus from Tahiti, a primary objective of his first Pacific voyage. The astronomical event helped scientists calculate the distance from Earth to the Sun.", whyItMatters: "International scientific cooperation for the Venus transit observations established the model for collaborative research that drives modern science.", category: "Science" },
  { month: 6, day: 4, year: 1783, title: "Montgolfier Brothers Demo Hot Air Balloon", description: "The Montgolfier brothers demonstrated the first public hot air balloon flight at Annonay, France. Their unmanned balloon rose to about 6,000 feet.", whyItMatters: "The Montgolfier flight began the age of human aviation, fulfilling humanity's ancient dream of flight and opening the path to modern air travel.", category: "Technology" },
  { month: 6, day: 5, year: 1723, title: "Adam Smith Born", description: "Adam Smith was born in Kirkcaldy, Scotland. His work The Wealth of Nations became the foundational text of modern economics and free-market capitalism.", whyItMatters: "Smith's ideas about markets, specialization, and the invisible hand continue to shape economic policy and debate around the world.", category: "Economics" },
  { month: 6, day: 6, year: 1944, title: "D-Day: Allied Invasion of Normandy", description: "Over 156,000 Allied troops landed on the beaches of Normandy in the largest seaborne invasion in history. The operation began the liberation of Western Europe from Nazi occupation.", whyItMatters: "D-Day demonstrated that free nations, working together, can overcome tyranny, and it reshaped the post-war international order.", category: "War" },
  { month: 6, day: 7, year: 1494, title: "Treaty of Tordesillas", description: "Spain and Portugal signed the Treaty of Tordesillas, dividing the newly discovered lands outside Europe between them along a meridian 370 leagues west of the Cape Verde islands.", whyItMatters: "This arbitrary division of the globe between two European powers set patterns of colonization whose effects on languages, cultures, and borders persist today.", category: "Diplomacy" },
  { month: 6, day: 8, year: 632, title: "Prophet Muhammad Dies", description: "The Prophet Muhammad died in Medina, having unified the Arabian Peninsula under Islam. His teachings would spread across three continents within a century of his death.", whyItMatters: "Islam's rapid spread created one of the world's great civilizations, preserving and advancing knowledge during Europe's Dark Ages.", category: "Culture" },
  { month: 6, day: 9, year: 1870, title: "Charles Dickens Dies", description: "Charles Dickens died at age 58, leaving his final novel The Mystery of Edwin Drood unfinished. He was mourned as the greatest novelist of the Victorian era.", whyItMatters: "Dickens's social novels helped create modern concepts of childhood welfare, labor rights, and the responsibility of society toward its most vulnerable.", category: "Culture" },
  { month: 6, day: 10, year: 1190, title: "Frederick Barbarossa Drowns", description: "Holy Roman Emperor Frederick Barbarossa drowned while crossing the Saleph River during the Third Crusade. His death demoralized the German crusading army.", whyItMatters: "Barbarossa's accidental death shows how random events can alter the course of history, and how dependent military campaigns are on their leaders.", category: "War" },
  { month: 6, day: 11, year: 1509, title: "Henry VIII Marries Catherine of Aragon", description: "Henry VIII married Catherine of Aragon, his first of six wives. Their inability to produce a male heir would lead to England's break from the Catholic Church.", whyItMatters: "This marriage's failure to produce a male heir reshaped English religion, politics, and culture in ways that still influence the world today.", category: "Politics" },
  { month: 6, day: 12, year: 1776, title: "Virginia Declaration of Rights", description: "Virginia adopted its Declaration of Rights, written primarily by George Mason. This document directly influenced the US Bill of Rights and the French Declaration of the Rights of Man.", whyItMatters: "The Virginia Declaration established that rights are inherent to individuals, not granted by governments, a principle that underpins modern human rights law.", category: "Politics" },
  { month: 6, day: 13, year: 323, title: "Alexander the Great Dies", description: "Alexander the Great died in Babylon at age 32 after a brief illness. His empire, stretching from Greece to India, was the largest the world had ever seen.", whyItMatters: "Alexander's conquests spread Greek culture across Asia, creating the Hellenistic world that blended Eastern and Western traditions and influenced the Roman Empire.", category: "War" },
  { month: 6, day: 14, year: 1777, title: "Stars and Stripes Adopted", description: "The Continental Congress adopted the Stars and Stripes as the flag of the United States. The flag has been modified 27 times as new states joined the union.", whyItMatters: "National symbols create shared identity and purpose, and the American flag's evolution reflects the nation's ongoing expansion and transformation.", category: "Politics" },
  { month: 6, day: 15, year: 1215, title: "Magna Carta Sealed", description: "King John of England sealed the Magna Carta at Runnymede, establishing that the king was subject to law. This foundational document limited royal authority and protected individual rights.", whyItMatters: "The Magna Carta established the principle that no one is above the law, a cornerstone of constitutional democracy worldwide.", category: "Politics" },
  { month: 6, day: 16, year: 1903, title: "Ford Motor Company Founded", description: "Henry Ford founded the Ford Motor Company in Detroit. His introduction of assembly line production would revolutionize manufacturing and create the modern middle class.", whyItMatters: "Ford's mass production methods transformed not just automobiles but all manufacturing, making consumer goods affordable for ordinary workers.", category: "Technology" },
  { month: 6, day: 17, year: 1775, title: "Battle of Bunker Hill", description: "Colonial militia fought British regulars at Bunker Hill near Boston. Though the British won the hill, they suffered devastating casualties that proved the colonists could fight.", whyItMatters: "Bunker Hill showed that determined defenders can inflict enormous costs on attackers, a lesson that influenced military strategy for centuries.", category: "War" },
  { month: 6, day: 18, year: 1815, title: "Battle of Waterloo", description: "Napoleon was decisively defeated by British and Prussian forces at Waterloo in Belgium. The battle ended Napoleon's rule and reshaped the European balance of power for a century.", whyItMatters: "Waterloo established the post-Napoleonic order and became synonymous with decisive, final defeat in political and military vocabulary.", category: "War" },
  { month: 6, day: 19, year: 1865, title: "Juneteenth: Emancipation Reaches Texas", description: "Union soldiers arrived in Galveston, Texas, and announced that all enslaved people were free, more than two years after the Emancipation Proclamation.", whyItMatters: "Juneteenth reminds us that declaring rights and actually implementing them are different challenges, and that freedom requires enforcement.", category: "Politics" },
  { month: 6, day: 20, year: 451, title: "Battle of the Catalaunian Plains", description: "A Roman-Visigothic alliance defeated Attila the Hun in one of the most significant battles in Western history. The defeat halted the Hunnic invasion of Gaul.", whyItMatters: "This battle demonstrated that even bitter rivals can unite against existential threats, preserving Western European civilization at a critical moment.", category: "War" },
  { month: 6, day: 21, year: 1788, title: "US Constitution Ratified", description: "New Hampshire became the ninth state to ratify the Constitution, meeting the threshold required for the document to take effect. The United States as we know it was born.", whyItMatters: "The ratification process showed that democratic consent requires persuasion and compromise, setting the template for constitutional governance.", category: "Politics" },
  { month: 6, day: 22, year: 1633, title: "Galileo Forced to Recant", description: "Galileo Galilei was forced by the Inquisition to recant his support of the heliocentric model. According to legend, he muttered 'And yet it moves' after his recantation.", whyItMatters: "Galileo's trial remains the defining example of institutional power suppressing scientific truth, a tension that continues in various forms.", category: "Science" },
  { month: 6, day: 23, year: 1314, title: "Battle of Bannockburn", description: "Scottish forces under Robert the Bruce defeated a much larger English army at Bannockburn. The victory secured Scottish independence for over three centuries.", whyItMatters: "Bannockburn demonstrates that tactical brilliance and knowledge of terrain can overcome numerical superiority, and that national identity can be forged through resistance.", category: "War" },
  { month: 6, day: 24, year: 1497, title: "John Cabot Reaches North America", description: "Italian explorer John Cabot, sailing for England, reached the coast of North America. His voyage established England's claim to the continent.", whyItMatters: "Cabot's voyage laid the foundation for British colonization of North America, ultimately producing the United States and Canada.", category: "Exploration" },
  { month: 6, day: 25, year: 1876, title: "Battle of Little Bighorn", description: "Lakota, Northern Cheyenne, and Arapaho warriors defeated the US 7th Cavalry under George Custer. The battle became the most famous clash of the Indian Wars.", whyItMatters: "Little Bighorn symbolizes indigenous resistance to colonization and the consequences of arrogance and underestimating opponents.", category: "War" },
  { month: 6, day: 26, year: 1483, title: "Richard III Takes the Throne", description: "Richard III usurped the English throne from his nephew Edward V. His short, controversial reign ended at Bosworth Field, and the fate of the Princes in the Tower remains a mystery.", whyItMatters: "Richard's story, immortalized by Shakespeare, illustrates how history is written by the victors and how political narratives shape reputation across centuries.", category: "Politics" },
  { month: 6, day: 27, year: 1358, title: "Battle of Brignais", description: "Free companies of unemployed soldiers defeated a French royal army at Brignais. These roving bands of mercenaries terrorized France after the Treaty of Bretigny.", whyItMatters: "The free companies demonstrate the danger of demobilized military forces without economic opportunities, a challenge faced after many modern conflicts.", category: "War" },
  { month: 6, day: 28, year: 1914, title: "Assassination of Archduke Franz Ferdinand", description: "Archduke Franz Ferdinand of Austria was assassinated in Sarajevo by Gavrilo Princip. This single act triggered a chain of alliances that plunged Europe into World War I.", whyItMatters: "The assassination shows how interconnected alliance systems can turn a local crisis into global catastrophe, a warning for modern geopolitics.", category: "War" },
  { month: 6, day: 29, year: 1613, title: "Globe Theatre Burns Down", description: "Shakespeare's Globe Theatre burned to the ground during a performance of Henry VIII when a theatrical cannon misfired and ignited the thatched roof.", whyItMatters: "The Globe's destruction and rebuilding symbolize the resilience of cultural institutions, and its modern reconstruction continues to bring Shakespeare to life.", category: "Culture" },
  { month: 6, day: 30, year: 1905, title: "Einstein Publishes Special Relativity", description: "Albert Einstein submitted his paper on special relativity, introducing the equation E=mc2. This 'miracle year' paper fundamentally changed physics.", whyItMatters: "Special relativity revealed that space and time are interconnected, enabling technologies from GPS to particle accelerators.", category: "Science" },

  // July through December - key dates
  { month: 7, day: 1, year: 1867, title: "Canadian Confederation", description: "The British North America Act united the provinces of Canada, Nova Scotia, and New Brunswick into the Dominion of Canada. This peaceful creation of a nation offered an alternative to revolution.", whyItMatters: "Canada's confederation through negotiation rather than revolution demonstrates that nations can be built through compromise and diplomacy.", category: "Politics" },
  { month: 7, day: 4, year: 1776, title: "US Declaration of Independence", description: "The Continental Congress adopted the Declaration of Independence, declaring the thirteen colonies free from British rule. Thomas Jefferson's words articulated universal principles of human rights.", whyItMatters: "The Declaration's assertion that all people possess unalienable rights became the philosophical foundation for democratic movements worldwide.", category: "Revolution" },
  { month: 7, day: 14, year: 1789, title: "Storming of the Bastille", description: "Parisian revolutionaries stormed the Bastille fortress, a symbol of royal tyranny. This event marked the beginning of the French Revolution and the end of absolute monarchy in France.", whyItMatters: "The storming of the Bastille demonstrated that popular uprising can topple entrenched power, inspiring revolutionary movements for over two centuries.", category: "Revolution" },
  { month: 7, day: 20, year: 1969, title: "Apollo 11 Moon Landing", description: "Neil Armstrong and Buzz Aldrin became the first humans to walk on the Moon. Armstrong's words upon stepping onto the lunar surface were heard by an estimated 600 million people.", whyItMatters: "The Moon landing proved that humanity can achieve seemingly impossible goals through sustained investment, cooperation, and scientific excellence.", category: "Science" },
  { month: 7, day: 28, year: 1914, title: "World War I Begins", description: "Austria-Hungary declared war on Serbia, setting off a chain of alliances that engulfed Europe in war. The conflict would kill over 16 million people and reshape the global order.", whyItMatters: "World War I's devastating consequences led to the League of Nations and eventually the United Nations, establishing the principle that war should be a last resort.", category: "War" },

  { month: 8, day: 6, year: 1945, title: "Atomic Bomb Dropped on Hiroshima", description: "The United States dropped an atomic bomb on Hiroshima, Japan, killing an estimated 80,000 people instantly. The bombing ushered in the nuclear age.", whyItMatters: "Hiroshima raised fundamental questions about the ethics of warfare and technology that humanity continues to grapple with in the nuclear age.", category: "War" },
  { month: 8, day: 15, year: 1947, title: "India Gains Independence", description: "India gained independence from Britain after nearly 200 years of colonial rule. Mahatma Gandhi's nonviolent resistance movement had shown the world a new path to freedom.", whyItMatters: "Indian independence and Gandhi's methods inspired civil rights and anti-colonial movements worldwide, proving nonviolence can defeat empires.", category: "Revolution" },
  { month: 8, day: 24, year: 79, title: "Eruption of Mount Vesuvius", description: "Mount Vesuvius erupted, burying the Roman cities of Pompeii and Herculaneum under volcanic ash. The preserved cities provide an unparalleled window into Roman daily life.", whyItMatters: "Pompeii's preservation reminds us of nature's power and provides invaluable archaeological evidence of how ancient people actually lived.", category: "Science" },

  { month: 9, day: 1, year: 1939, title: "Germany Invades Poland", description: "Nazi Germany invaded Poland, beginning World War II in Europe. The invasion introduced blitzkrieg warfare and triggered declarations of war from Britain and France.", whyItMatters: "The invasion of Poland showed the catastrophic consequences of appeasement and the importance of collective security against aggression.", category: "War" },
  { month: 9, day: 11, year: 1297, title: "Battle of Stirling Bridge", description: "William Wallace and Andrew Moray led Scottish forces to a stunning victory over the English at Stirling Bridge. The battle became a defining moment in Scottish national identity.", whyItMatters: "Stirling Bridge showed that tactical innovation and fighting spirit can overcome a larger, better-equipped army, and cemented Wallace as a national hero.", category: "War" },
  { month: 9, day: 22, year: 1692, title: "Last Salem Witch Trials Hangings", description: "Eight people were hanged in Salem, Massachusetts, in the final executions of the Salem witch trials. In total, twenty people were executed during the mass hysteria.", whyItMatters: "The Salem trials remain a powerful warning about mass hysteria, false accusations, and the dangers of allowing fear to override due process.", category: "Politics" },

  { month: 10, day: 12, year: 1492, title: "Columbus Reaches the Americas", description: "Christopher Columbus's expedition made landfall in the Bahamas, beginning sustained contact between Europe and the Americas. This encounter transformed both hemispheres.", whyItMatters: "Columbus's voyage launched the Columbian Exchange, transforming global agriculture, demographics, and trade patterns that define the modern world.", category: "Exploration" },
  { month: 10, day: 14, year: 1066, title: "Battle of Hastings", description: "William the Conqueror defeated King Harold II at the Battle of Hastings, beginning the Norman Conquest of England. This single battle reshaped the English language, law, and culture.", whyItMatters: "The Norman Conquest transformed England from an Anglo-Saxon kingdom into a feudal state, introducing French influences that shaped modern English.", category: "War" },
  { month: 10, day: 31, year: 1517, title: "Luther Posts 95 Theses", description: "Martin Luther nailed his 95 Theses to the door of All Saints' Church in Wittenberg, challenging the Catholic Church's sale of indulgences. This act sparked the Protestant Reformation.", whyItMatters: "Luther's challenge to institutional corruption established the principle that individuals can hold powerful institutions accountable.", category: "Culture" },

  { month: 11, day: 5, year: 1605, title: "Gunpowder Plot Discovered", description: "Guy Fawkes was discovered guarding 36 barrels of gunpowder beneath the English Parliament. The foiled plot to blow up the House of Lords saved the lives of King James I and the members of Parliament.", whyItMatters: "The Gunpowder Plot's legacy includes enhanced state surveillance and security measures, raising enduring questions about balancing security and civil liberties.", category: "Politics" },
  { month: 11, day: 9, year: 1989, title: "Fall of the Berlin Wall", description: "The Berlin Wall fell as East German authorities opened the border. Jubilant crowds from both sides climbed the wall and began tearing it down, symbolizing the end of the Cold War.", whyItMatters: "The wall's fall demonstrated that no barrier can permanently suppress human desire for freedom, and that peaceful revolution is possible.", category: "Revolution" },
  { month: 11, day: 11, year: 1918, title: "World War I Armistice", description: "The armistice ending World War I took effect at the eleventh hour of the eleventh day of the eleventh month. After four years of devastating trench warfare, the guns finally fell silent.", whyItMatters: "The armistice's legacy lives on in Veterans Day and Remembrance Day, honoring the sacrifices of those who serve in the armed forces.", category: "War" },
  { month: 11, day: 22, year: 1963, title: "President Kennedy Assassinated", description: "President John F. Kennedy was assassinated in Dallas, Texas. His death shocked the nation and the world, and continues to generate debate and investigation.", whyItMatters: "Kennedy's assassination marked a loss of innocence for a generation and raised enduring questions about political violence and conspiracy.", category: "Politics" },

  { month: 12, day: 1, year: 1955, title: "Rosa Parks Refuses to Give Up Her Seat", description: "Rosa Parks refused to give up her bus seat to a white passenger in Montgomery, Alabama. Her arrest sparked the Montgomery Bus Boycott and became a catalyst for the civil rights movement.", whyItMatters: "Parks's act of courage shows that individual resistance to injustice can ignite movements that transform entire societies.", category: "Revolution" },
  { month: 12, day: 7, year: 1941, title: "Attack on Pearl Harbor", description: "Japan launched a surprise military attack on the US naval base at Pearl Harbor, Hawaii. The attack killed over 2,400 Americans and drew the United States into World War II.", whyItMatters: "Pearl Harbor transformed American foreign policy from isolationism to global engagement, reshaping the world order.", category: "War" },
  { month: 12, day: 16, year: 1773, title: "Boston Tea Party", description: "American colonists disguised as Mohawk Indians dumped 342 chests of British East India Company tea into Boston Harbor to protest taxation without representation.", whyItMatters: "The Boston Tea Party established direct action as a form of political protest and became the defining symbol of resistance to unjust taxation.", category: "Revolution" },
  { month: 12, day: 17, year: 1903, title: "Wright Brothers' First Flight", description: "Orville and Wilbur Wright achieved the first sustained, controlled, powered heavier-than-air flight at Kitty Hawk, North Carolina. The flight lasted 12 seconds and covered 120 feet.", whyItMatters: "The Wright brothers' achievement launched the aviation age, transforming warfare, commerce, and human mobility within a single generation.", category: "Technology" },
  { month: 12, day: 25, year: 800, title: "Charlemagne Crowned Holy Roman Emperor", description: "Pope Leo III crowned Charlemagne as Emperor of the Romans on Christmas Day. This act created the concept of a renewed Roman Empire in the West.", whyItMatters: "Charlemagne's coronation established the relationship between church and state that would define European politics for a millennium.", category: "Politics" },
  { month: 12, day: 31, year: 1695, title: "Window Tax Introduced in England", description: "King William III introduced the Window Tax in England, taxing houses based on the number of windows. Many homeowners bricked up windows to avoid the tax.", whyItMatters: "The Window Tax demonstrates how taxation creates unintended consequences, as people alter behavior to avoid charges, a principle central to modern tax policy.", category: "Economics" },
];

export function getEventForDate(month: number, day: number): HistoricalDayEvent | null {
  return thisDayEvents.find((e) => e.month === month && e.day === day) || null;
}

export function getEventsNearDate(month: number, day: number, range: number = 3): HistoricalDayEvent[] {
  const results: HistoricalDayEvent[] = [];
  for (let offset = -range; offset <= range; offset++) {
    const date = new Date(2024, month - 1, day + offset);
    const m = date.getMonth() + 1;
    const d = date.getDate();
    const event = thisDayEvents.find((e) => e.month === m && e.day === d);
    if (event) results.push(event);
  }
  return results;
}

const fallbackEvents: HistoricalDayEvent[] = [
  { month: 0, day: 0, year: 1440, title: "Gutenberg Invents the Printing Press", description: "Around this time, Johannes Gutenberg developed the movable-type printing press in Mainz, Germany. His invention would democratize knowledge and transform human civilization.", whyItMatters: "The printing press enabled mass literacy, the Reformation, and the Scientific Revolution, making it one of history's most transformative inventions.", category: "Technology" },
  { month: 0, day: 0, year: 1687, title: "Newton Publishes Principia Mathematica", description: "Isaac Newton published his Principia Mathematica, laying out the laws of motion and universal gravitation. The work is considered one of the most important scientific publications ever.", whyItMatters: "Newton's laws provided the mathematical framework for understanding the physical world, enabling everything from bridge building to space travel.", category: "Science" },
  { month: 0, day: 0, year: 1776, title: "Adam Smith Publishes The Wealth of Nations", description: "Adam Smith published An Inquiry into the Nature and Causes of the Wealth of Nations. The book became the foundational text of modern economics.", whyItMatters: "Smith's analysis of free markets, division of labor, and the invisible hand continues to shape economic policy debates worldwide.", category: "Economics" },
];

export function getFallbackEvent(): HistoricalDayEvent {
  const idx = Math.floor(Math.random() * fallbackEvents.length);
  return fallbackEvents[idx];
}
